function NowAssistPanelMessageAutoExpand()
{
  var shellWin = window;
  try {
    var topWin = window.top;
    if (topWin && topWin.document) shellWin = topWin;
  } catch (e) {
    shellWin = window;
  }

  var existing = null;
  try {
    existing = shellWin["__nowAssistAutoExpandV7"];
  } catch (e2) {
    existing = null;
  }

  if (existing && typeof existing["start"] === "function") {
    existing["start"]();
    return existing;
  }

  var CFG = {
    intervalMs: 250,
    rescanMs: 2000
  };

  function timeNow()
  {
    return GetTimeNow();
  }

  var state = {
    running: false,
    intervalId: null,
    tickScheduled: false,
    lastRescan: 0,
    searchRoots: [],
    observedTargets: [],
    observers: [],
    installedWindows: [],
    observedFrames: [],
    patchedWindows: []
  };

  function containsRef(arr, item) {
    if (!arr || !item) return false;
    var i = 0;
    for (i = 0; i < arr.length; i += 1) {
      if (arr[i] === item) return true;
    }
    return false;
  }

  function pushUnique(arr, item) {
    if (!arr || !item) return;
    if (containsRef(arr, item)) return;
    arr.push(item);
  }

  function normalizeObserveTarget(target) {
    if (!target) return null;

    var nodeType = null;
    try {
      nodeType = target.nodeType;
    } catch (e) {
      nodeType = null;
    }

    if (nodeType === 9) {
      try {
        return target.documentElement || target.body || null;
      } catch (e2) {
        return null;
      }
    }

    return target;
  }

  function scheduleTick() {
    if (state["tickScheduled"]) return;
    state["tickScheduled"] = true;

    var to = null;
    try {
      to = shellWin.setTimeout;
    } catch (e) {
      to = null;
    }
    if (typeof to !== "function") return;

    to(function () {
      state["tickScheduled"] = false;
      tick();
    }, 20);
  }

  function addSearchRoot(root) {
    if (!root) return;
    pushUnique(state["searchRoots"], root);
    observeTarget(root);
  }

  function ensureStyleInjected(doc) {
    if (!doc) return;

    var head = null;
    try {
      head = doc.head;
    } catch (e) {
      head = null;
    }
    if (!head) return;

    var existingStyle = null;
    try {
      existingStyle = doc.getElementById("nowassist-autoexpand-style");
    } catch (e2) {
      existingStyle = null;
    }
    if (existingStyle) return;

    var style = null;
    try {
      style = doc.createElement("style");
    } catch (e3) {
      style = null;
    }
    if (!style) return;

    try {
      style.id = "nowassist-autoexpand-style";
      style.type = "text/css";
      style.appendChild(
        doc.createTextNode(
          ".nowassist-autoexpanded{display:flex !important;max-height:none !important;height:auto !important;overflow:visible !important;-webkit-line-clamp:unset !important;}" +
          ".nowassist-hide-toggle{display:none !important;}"
        )
      );
      head.appendChild(style);
    } catch (e4) {}
  }

  function addClass(el, className) {
    if (!el) return;
    var cl = null;
    try {
      cl = el.classList;
    } catch (e) {
      cl = null;
    }
    if (!cl) return;

    try {
      cl.add(className);
    } catch (e2) {}
  }

  function setImportantStyle(el, prop, value) {
    if (!el) return;
    var st = null;
    try {
      st = el.style;
    } catch (e) {
      st = null;
    }
    if (!st) return;

    var sp = null;
    try {
      sp = st.setProperty;
    } catch (e2) {
      sp = null;
    }
    if (typeof sp !== "function") return;

    try {
      sp.call(st, prop, value, "important");
    } catch (e3) {}
  }

  function forceExpand(el) {
    if (!el) return;

    addClass(el, "nowassist-autoexpanded");

    setImportantStyle(el, "display", "flex");
    setImportantStyle(el, "max-height", "none");
    setImportantStyle(el, "height", "auto");
    setImportantStyle(el, "overflow", "visible");
    setImportantStyle(el, "-webkit-line-clamp", "unset");
  }

  function hideShowToggle(labelEl) {
    if (!labelEl) return;

    var txt = "";
    try {
      txt = labelEl.textContent || "";
    } catch (e) {
      txt = "";
    }

    txt = String(txt);
    txt = txt.replace(/\s+/g, " ");
    txt = txt.trim();
    txt = txt.toLowerCase();

    if (txt !== "show more" && txt !== "show less") return;

    var container = null;

    var closestFn = null;
    try {
      closestFn = labelEl.closest;
    } catch (e2) {
      closestFn = null;
    }

    if (typeof closestFn === "function") {
      try {
        container = closestFn.call(labelEl, "now-button-bar");
      } catch (e3) {
        container = null;
      }
      if (!container) {
        try {
          container = closestFn.call(labelEl, "button");
        } catch (e4) {
          container = null;
        }
      }
      if (!container) {
        try {
          container = closestFn.call(labelEl, ".now-button-bar");
        } catch (e5) {
          container = null;
        }
      }
    }

    if (!container) {
      try {
        container = labelEl.parentNode;
      } catch (e6) {
        container = null;
      }
    }

    if (!container) return;

    addClass(container, "nowassist-hide-toggle");
    setImportantStyle(container, "display", "none");
  }

  function deepQueryAll(root, selector) {
    var results = [];
    if (!root) return results;

    var queue = [root];
    var seenRoots = [];
    var seenNodes = [];

    function rootWasSeen(r) {
      var i = 0;
      for (i = 0; i < seenRoots.length; i += 1) {
        if (seenRoots[i] === r) return true;
      }
      return false;
    }

    function addNodeUnique(node) {
      var i = 0;
      for (i = 0; i < seenNodes.length; i += 1) {
        if (seenNodes[i] === node) return;
      }
      seenNodes.push(node);
      results.push(node);
    }

    while (queue.length) {
      var r = queue.shift();
      if (!r) continue;
      if (rootWasSeen(r)) continue;
      seenRoots.push(r);

      var found = [];
      try {
        found = r.querySelectorAll(selector);
      } catch (e) {
        found = [];
      }

      var i2 = 0;
      for (i2 = 0; i2 < found.length; i2 += 1) {
        if (found[i2]) addNodeUnique(found[i2]);
      }

      var els = [];
      try {
        els = r.querySelectorAll("*");
      } catch (e2) {
        els = [];
      }

      var j = 0;
      for (j = 0; j < els.length; j += 1) {
        var el = els[j];
        if (!el) continue;

        var sr = null;
        try {
          sr = el.shadowRoot;
        } catch (e3) {
          sr = null;
        }
        if (sr) queue.push(sr);
      }
    }

    return results;
  }

  function installIframe(frame) {
    if (!frame) return;

    if (!containsRef(state["observedFrames"], frame)) {
      var addEv = null;
      try {
        addEv = frame.addEventListener;
      } catch (e) {
        addEv = null;
      }

      if (typeof addEv === "function") {
        try {
          addEv.call(
            frame,
            "load",
            function () {
              try {
                var cw = frame.contentWindow;
                if (cw) installWindowHooks(cw);
              } catch (e2) {}
              scheduleTick();
            },
            false
          );
        } catch (e3) {}
      }

      state["observedFrames"].push(frame);
    }

    try {
      var cw2 = frame.contentWindow;
      if (cw2 && cw2.document) installWindowHooks(cw2);
    } catch (e4) {}
  }

  function scanNode(node) {
    if (!node) return;

    var nodeType = null;
    try {
      nodeType = node.nodeType;
    } catch (e) {
      nodeType = null;
    }

    if (nodeType === 9) {
      try {
        ensureStyleInjected(node);
      } catch (e2) {}

      addSearchRoot(node);

      var docRoot = null;
      try {
        docRoot = node.documentElement || node.body;
      } catch (e3) {
        docRoot = null;
      }
      if (docRoot) observeTarget(docRoot);
    }

    if (nodeType !== 1 && nodeType !== 9 && nodeType !== 11) return;

    var tag = String(node.tagName || "");
	tag = tag.toLowerCase();

    if (tag === "iframe") {
      installIframe(node);
    }

    var sr = null;
    try {
      sr = node.shadowRoot;
    } catch (e5) {
      sr = null;
    }
    if (sr) addSearchRoot(sr);

    var descendants = [];
    try {
      if (typeof node.querySelectorAll === "function") {
        descendants = node.querySelectorAll("*");
      }
    } catch (e6) {
      descendants = [];
    }

    var i = 0;
    for (i = 0; i < descendants.length; i += 1) {
      var el = descendants[i];
      if (!el) continue;

      var subTag = String(el.tagName || "");
	  subTag = subTag.toLowerCase();

      if (subTag === "iframe") {
        installIframe(el);
      }

      var subSr = null;
      try {
        subSr = el.shadowRoot;
      } catch (e8) {
        subSr = null;
      }
      if (subSr) addSearchRoot(subSr);
    }
  }

  function handleMutations(mutations) {
    if (!mutations || !mutations.length) return;

    var i = 0;
    for (i = 0; i < mutations.length; i += 1) {
      var m = mutations[i];
      if (!m) continue;

      var target = null;
      try {
        target = m.target;
      } catch (e) {
        target = null;
      }

      if (target) {
        var targetSr = null;
        try {
          targetSr = target.shadowRoot;
        } catch (e2) {
          targetSr = null;
        }
        if (targetSr) addSearchRoot(targetSr);
      }

      var added = null;
      try {
        added = m.addedNodes;
      } catch (e3) {
        added = null;
      }

      if (!added || !added.length) continue;

      var j = 0;
      for (j = 0; j < added.length; j += 1) {
        var node = added[j];
        if (!node) continue;
        scanNode(node);
      }
    }
  }

  function observeTarget(target) {
    var observeNode = normalizeObserveTarget(target);
    if (!observeNode) return;
    if (containsRef(state["observedTargets"], observeNode)) return;

    var ownerWin = shellWin;
    try {
      if (observeNode.ownerDocument && observeNode.ownerDocument.defaultView) {
        ownerWin = observeNode.ownerDocument.defaultView;
      }
    } catch (e) {
      ownerWin = shellWin;
    }

    var MO = null;
    try {
      MO = ownerWin["MutationObserver"] || shellWin["MutationObserver"];
    } catch (e2) {
      MO = null;
    }
    if (!MO) return;

    var mo = null;
    try {
      mo = new MO(function (mutations) {
        handleMutations(mutations);
        scheduleTick();
      });
    } catch (e3) {
      mo = null;
    }
    if (!mo) return;

    try {
      mo.observe(observeNode, {
        childList: true,
        subtree: true,
        attributes: true
      });
    } catch (e4) {
      try {
        mo.disconnect();
      } catch (e5) {}
      return;
    }

    state["observedTargets"].push(observeNode);
    state["observers"].push(mo);
  }

  function patchAttachShadow(win) {
    if (!win) return;
    if (containsRef(state["patchedWindows"], win)) return;

    var ElementCtor = null;
    try {
      ElementCtor = win.Element;
    } catch (e) {
      ElementCtor = null;
    }
    if (!ElementCtor || !ElementCtor.prototype) return;

    var proto = ElementCtor.prototype;
    var original = null;
    try {
      original = proto.attachShadow;
    } catch (e2) {
      original = null;
    }
    if (typeof original !== "function") {
      state["patchedWindows"].push(win);
      return;
    }

    try {
      if (proto["__nowAssistAutoExpandAttachShadowPatched"]) {
        state["patchedWindows"].push(win);
        return;
      }
    } catch (e3) {}

    try {
      proto.attachShadow = function () {
        var root = original.apply(this, arguments);

        try {
          addSearchRoot(root);
        } catch (e4) {}

        try {
          scanNode(this);
        } catch (e5) {}

        scheduleTick();
        return root;
      };

      try {
        proto["__nowAssistAutoExpandAttachShadowPatched"] = true;
      } catch (e6) {}

      state["patchedWindows"].push(win);
    } catch (e7) {}
  }

  function installWindowHooks(win) {
    if (!win) return;
    if (containsRef(state["installedWindows"], win)) return;

    var doc = null;
    try {
      doc = win.document;
    } catch (e) {
      doc = null;
    }
    if (!doc) return;

    state["installedWindows"].push(win);

    patchAttachShadow(win);

    ensureStyleInjected(doc);
    addSearchRoot(doc);

    var rootNode = null;
    try {
      rootNode = doc.documentElement || doc.body;
    } catch (e2) {
      rootNode = null;
    }
    if (rootNode) observeTarget(rootNode);

    scanNode(doc);
  }

  function rescanInstalledWindows() {
    var now = timeNow();
    if (now - state["lastRescan"] < CFG["rescanMs"]) return;
    state["lastRescan"] = now;

    var i = 0;
    for (i = 0; i < state["installedWindows"].length; i += 1) {
      var win = state["installedWindows"][i];
      if (!win) continue;

      try {
        patchAttachShadow(win);
      } catch (e) {}

      try {
        if (win.document) scanNode(win.document);
      } catch (e2) {}
    }
  }

  function observeOpenShadowRootsUnder(root) {
    var els = deepQueryAll(root, "*");
    var i = 0;
    for (i = 0; i < els.length; i += 1) {
      var el = els[i];
      if (!el) continue;

      var sr = null;
      try {
        sr = el.shadowRoot;
      } catch (e) {
        sr = null;
      }
      if (sr) addSearchRoot(sr);
    }
  }

  function enforceInRoot(root) {
    if (!root) return;

    var targets = deepQueryAll(
      root,
      ".sn-cs-rich-text-height-wrapper.truncateable.expandable, .sn-cs-rich-text-container"
    );

    var i = 0;
    for (i = 0; i < targets.length; i += 1) {
      var t = targets[i];
      if (t) forceExpand(t);
    }

    var labels = deepQueryAll(root, ".now-button-bar-label");
    var j = 0;
    for (j = 0; j < labels.length; j += 1) {
      var lab = labels[j];
      if (lab) hideShowToggle(lab);
    }

    observeTarget(root);
    observeOpenShadowRootsUnder(root);
  }

  function tick() {
    rescanInstalledWindows();

    var i = 0;
    for (i = 0; i < state["searchRoots"].length; i += 1) {
      var r = state["searchRoots"][i];
      if (r) enforceInRoot(r);
    }
  }

  var controller = {
    start: function () {
      if (state["running"]) return;
      state["running"] = true;

      installWindowHooks(shellWin);
      tick();

      var si = null;
      try {
        si = shellWin.setInterval;
      } catch (e) {
        si = null;
      }

      if (typeof si === "function") {
        state["intervalId"] = si(function () {
          tick();
        }, CFG["intervalMs"]);
      }
    },

    stop: function () {
      state["running"] = false;

      var ci = null;
      try {
        ci = shellWin.clearInterval;
      } catch (e) {
        ci = null;
      }
      if (typeof ci === "function" && state["intervalId"]) {
        ci(state["intervalId"]);
      }
      state["intervalId"] = null;

      var i = 0;
      for (i = 0; i < state["observers"].length; i += 1) {
        var mo = state["observers"][i];
        if (!mo) continue;

        try {
          if (typeof mo.disconnect === "function") mo.disconnect();
        } catch (e2) {}
      }

      state["observers"] = [];
      state["observedTargets"] = [];
      state["searchRoots"] = [];
      state["installedWindows"] = [];
      state["observedFrames"] = [];
      state["patchedWindows"] = [];
      state["tickScheduled"] = false;
    }
  };

  try {
    shellWin["__nowAssistAutoExpandV7"] = controller;
  } catch (e) {}

  controller.start();
  return controller;
}
